    "C#": "<span class=\"kw\">public interface</span> <span class=\"cl\">ICmd</span> {\n  <span class=\"kw\">void</span> <span class=\"fn\">Execute</span>();\n  <span class=\"kw\">void</span> <span class=\"fn\">Undo</span>();\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">AppendCmd</span>(<span class=\"cl\">StringBuilder</span> <span class=\"dc\">b</span>, <span class=\"kw\">string</span> <span class=\"dc\">t</span>) : <span class=\"cl\">ICmd</span> {\n  <span class=\"kw\">public void</span> <span class=\"fn\">Execute</span>() =&gt; <span class=\"dc\">b</span>.<span class=\"fn\">Append</span>(<span class=\"dc\">t</span>);\n  <span class=\"kw\">public void</span> <span class=\"fn\">Undo</span>() =&gt;\n    <span class=\"dc\">b</span>.<span class=\"fn\">Remove</span>(<span class=\"dc\">b</span>.<span class=\"dc\">Length</span> - <span class=\"dc\">t</span>.<span class=\"dc\">Length</span>, <span class=\"dc\">t</span>.<span class=\"dc\">Length</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">History</span> {\n  <span class=\"cl\">Stack</span>&lt;<span class=\"cl\">ICmd</span>&gt; <span class=\"dc\">_s</span> = <span class=\"kw\">new</span>();\n  <span class=\"kw\">public void</span> <span class=\"fn\">Run</span>(<span class=\"cl\">ICmd</span> <span class=\"dc\">c</span>) { <span class=\"dc\">c</span>.<span class=\"fn\">Execute</span>(); <span class=\"dc\">_s</span>.<span class=\"fn\">Push</span>(<span class=\"dc\">c</span>); }\n  <span class=\"kw\">public void</span> <span class=\"fn\">Undo</span>() { <span class=\"kw\">if</span> (<span class=\"dc\">_s</span>.<span class=\"dc\">Count</span> > 0) <span class=\"dc\">_s</span>.<span class=\"fn\">Pop</span>().<span class=\"fn\">Undo</span>(); }\n}",
    "Python": "<span class=\"kw\">class</span> <span class=\"cl\">AppendCmd</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>, <span class=\"dc\">buf</span>, <span class=\"dc\">text</span>):\n    <span class=\"dc\">self.buf</span>, <span class=\"dc\">self.text</span> = <span class=\"dc\">buf</span>, <span class=\"dc\">text</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">execute</span>(<span class=\"dc\">self</span>): <span class=\"dc\">self.buf</span>.<span class=\"fn\">append</span>(<span class=\"dc\">self.text</span>)\n  <span class=\"kw\">def</span> <span class=\"fn\">undo</span>(<span class=\"dc\">self</span>):    <span class=\"dc\">self.buf</span>.<span class=\"fn\">pop</span>()\n\n\n<span class=\"kw\">class</span> <span class=\"cl\">History</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>): <span class=\"dc\">self.stack</span> = []\n\n  <span class=\"kw\">def</span> <span class=\"fn\">run</span>(<span class=\"dc\">self</span>, <span class=\"dc\">cmd</span>):\n    <span class=\"dc\">cmd</span>.<span class=\"fn\">execute</span>(); <span class=\"dc\">self.stack</span>.<span class=\"fn\">append</span>(<span class=\"dc\">cmd</span>)\n\n  <span class=\"kw\">def</span> <span class=\"fn\">undo</span>(<span class=\"dc\">self</span>):\n    <span class=\"kw\">if</span> <span class=\"dc\">self.stack</span>: <span class=\"dc\">self.stack</span>.<span class=\"fn\">pop</span>().<span class=\"fn\">undo</span>()",
