    "Java": "<span class=\"kw\">interface</span> <span class=\"cl\">HttpClient</span> {\n  <span class=\"cl\">String</span> <span class=\"fn\">get</span>(<span class=\"cl\">String</span> <span class=\"dc\">url</span>);\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">Base</span> <span class=\"kw\">implements</span> <span class=\"cl\">HttpClient</span> {\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">get</span>(<span class=\"cl\">String</span> <span class=\"dc\">u</span>) { <span class=\"kw\">return</span> <span class=\"st\">\"response\"</span>; }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">LogDecorator</span> <span class=\"kw\">implements</span> <span class=\"cl\">HttpClient</span> {\n  <span class=\"kw\">private final</span> <span class=\"cl\">HttpClient</span> <span class=\"dc\">inner</span>;\n  <span class=\"fn\">LogDecorator</span>(<span class=\"cl\">HttpClient</span> <span class=\"dc\">c</span>) { <span class=\"dc\">this</span>.<span class=\"dc\">inner</span> = <span class=\"dc\">c</span>; }\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">get</span>(<span class=\"cl\">String</span> <span class=\"dc\">u</span>) {\n    <span class=\"cl\">System</span>.out.<span class=\"fn\">println</span>(<span class=\"st\">\"\u2192 GET \"</span> + <span class=\"dc\">u</span>);\n    <span class=\"kw\">return</span> <span class=\"dc\">inner</span>.<span class=\"fn\">get</span>(<span class=\"dc\">u</span>);\n  }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">RetryDecorator</span> <span class=\"kw\">implements</span> <span class=\"cl\">HttpClient</span> {\n  <span class=\"kw\">private final</span> <span class=\"cl\">HttpClient</span> <span class=\"dc\">inner</span>; <span class=\"kw\">private final int</span> <span class=\"dc\">n</span>;\n  <span class=\"fn\">RetryDecorator</span>(<span class=\"cl\">HttpClient</span> <span class=\"dc\">c</span>, <span class=\"kw\">int</span> <span class=\"dc\">n</span>) { <span class=\"dc\">inner</span>=<span class=\"dc\">c</span>; <span class=\"dc\">this</span>.<span class=\"dc\">n</span>=<span class=\"dc\">n</span>; }\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">get</span>(<span class=\"cl\">String</span> <span class=\"dc\">u</span>) {\n    <span class=\"kw\">for</span> (<span class=\"kw\">int</span> <span class=\"dc\">i</span> = <span class=\"nm\">0</span>; <span class=\"dc\">i</span> &lt; <span class=\"dc\">n</span>; <span class=\"dc\">i</span>++)\n      <span class=\"kw\">try</span> { <span class=\"kw\">return</span> <span class=\"dc\">inner</span>.<span class=\"fn\">get</span>(<span class=\"dc\">u</span>); } <span class=\"kw\">catch</span> (<span class=\"cl\">Exception</span> <span class=\"dc\">e</span>) {}\n    <span class=\"kw\">throw new</span> <span class=\"cl\">RuntimeException</span>(<span class=\"st\">\"Max retries reached\"</span>);\n  }\n}",
    "C#": "<span class=\"kw\">public interface</span> <span class=\"cl\">IHttp</span> { <span class=\"kw\">string</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">url</span>); }\n\n<span class=\"kw\">public class</span> <span class=\"cl\">Base</span> : <span class=\"cl\">IHttp</span> {\n  <span class=\"kw\">public string</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">u</span>) =&gt; <span class=\"st\">\"response\"</span>;\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">Logging</span>(<span class=\"cl\">IHttp</span> <span class=\"dc\">inner</span>) : <span class=\"cl\">IHttp</span> {\n  <span class=\"kw\">public string</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">u</span>) {\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">$\"\u2192 GET {{u}}\"</span>);\n    <span class=\"kw\">return</span> <span class=\"dc\">inner</span>.<span class=\"fn\">Get</span>(<span class=\"dc\">u</span>);\n  }\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">Retry</span>(<span class=\"cl\">IHttp</span> <span class=\"dc\">inner</span>, <span class=\"kw\">int</span> <span class=\"dc\">n</span>) : <span class=\"cl\">IHttp</span> {\n  <span class=\"kw\">public string</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">u</span>) {\n    <span class=\"kw\">for</span> (<span class=\"kw\">int</span> <span class=\"dc\">i</span> = 0; <span class=\"dc\">i</span> &lt; <span class=\"dc\">n</span>; <span class=\"dc\">i</span>++)\n      <span class=\"kw\">try</span> { <span class=\"kw\">return</span> <span class=\"dc\">inner</span>.<span class=\"fn\">Get</span>(<span class=\"dc\">u</span>); } <span class=\"kw\">catch</span> {}\n    <span class=\"kw\">throw new</span> <span class=\"cl\">Exception</span>(<span class=\"st\">\"Max retries\"</span>);\n  }\n}",
    "Python": "<span class=\"kw\">from</span> functools <span class=\"kw\">import</span> wraps\n\n<span class=\"kw\">def</span> <span class=\"fn\">logged</span>(<span class=\"dc\">fn</span>):\n  <span class=\"dc\">@wraps</span>(<span class=\"dc\">fn</span>)\n  <span class=\"kw\">def</span> <span class=\"fn\">wrapper</span>(*<span class=\"dc\">a</span>, **<span class=\"dc\">k</span>):\n    <span class=\"fn\">print</span>(<span class=\"st\">f\"\u2192 {{fn.__name__}}\"</span>)\n    <span class=\"kw\">return</span> <span class=\"dc\">fn</span>(*<span class=\"dc\">a</span>, **<span class=\"dc\">k</span>)\n  <span class=\"kw\">return</span> <span class=\"dc\">wrapper</span>\n\n<span class=\"kw\">def</span> <span class=\"fn\">cached</span>(<span class=\"dc\">fn</span>):\n  <span class=\"dc\">_c</span> = {}\n  <span class=\"dc\">@wraps</span>(<span class=\"dc\">fn</span>)\n  <span class=\"kw\">def</span> <span class=\"fn\">wrapper</span>(<span class=\"dc\">url</span>):\n    <span class=\"kw\">if</span> <span class=\"dc\">url</span> <span class=\"kw\">not in</span> <span class=\"dc\">_c</span>: <span class=\"dc\">_c</span>[<span class=\"dc\">url</span>] = <span class=\"dc\">fn</span>(<span class=\"dc\">url</span>)\n    <span class=\"kw\">return</span> <span class=\"dc\">_c</span>[<span class=\"dc\">url</span>]\n  <span class=\"kw\">return</span> <span class=\"dc\">wrapper</span>\n\n<span class=\"dc\">@logged</span>\n<span class=\"dc\">@cached</span>\n<span class=\"kw\">def</span> <span class=\"fn\">fetch</span>(<span class=\"dc\">url</span>) -&gt; <span class=\"kw\">str</span>:\n  <span class=\"kw\">return</span> <span class=\"st\">\"response\"</span>",
    "Ruby": "<span class=\"kw\">module</span> <span class=\"cl\">Logging</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">get</span>(<span class=\"dc\">u</span>)\n    <span class=\"fn\">puts</span> <span class=\"st\">\"\u2192 GET #{{u}}\"</span>\n    <span class=\"kw\">super</span>\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">HttpClient</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">get</span>(<span class=\"dc\">u</span>) = <span class=\"st\">\"response\"</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">LogClient</span> &lt; <span class=\"cl\">HttpClient</span>\n  <span class=\"kw\">prepend</span> <span class=\"cl\">Logging</span>\n<span class=\"kw\">end</span>\n\n<span class=\"cl\">LogClient</span>.<span class=\"fn\">new</span>.<span class=\"fn\">get</span>(<span class=\"st\">\"https://api.example.com\"</span>)",
