    "C#": "<span class=\"kw\">public class</span> <span class=\"cl\">OrderFacade</span> {\n  <span class=\"kw\">readonly</span> <span class=\"cl\">Inventory</span> <span class=\"dc\">_inv</span> = <span class=\"kw\">new</span>();\n  <span class=\"kw\">readonly</span> <span class=\"cl\">Payment</span>  <span class=\"dc\">_pay</span> = <span class=\"kw\">new</span>();\n  <span class=\"kw\">readonly</span> <span class=\"cl\">Shipping</span> <span class=\"dc\">_shp</span> = <span class=\"kw\">new</span>();\n\n  <span class=\"kw\">public string</span> <span class=\"fn\">PlaceOrder</span>(<span class=\"kw\">string</span> <span class=\"dc\">sku</span>, <span class=\"kw\">decimal</span> <span class=\"dc\">price</span>) {\n    <span class=\"kw\">if</span> (!<span class=\"dc\">_inv</span>.<span class=\"fn\">Check</span>(<span class=\"dc\">sku</span>))\n      <span class=\"kw\">throw new</span> <span class=\"cl\">InvalidOperationException</span>(<span class=\"st\">\"Out of stock\"</span>);\n    <span class=\"dc\">_pay</span>.<span class=\"fn\">Charge</span>(<span class=\"dc\">price</span>);\n    <span class=\"kw\">return</span> <span class=\"dc\">_shp</span>.<span class=\"fn\">Ship</span>(<span class=\"dc\">sku</span>);\n  }\n}\n\n<span class=\"cm\">// var tracking = facade.PlaceOrder(\"SKU-001\", 99.90m);</span>",
    "Python": "<span class=\"kw\">class</span> <span class=\"cl\">OrderFacade</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>):\n    <span class=\"dc\">self._inv</span> = <span class=\"cl\">Inventory</span>()\n    <span class=\"dc\">self._pay</span> = <span class=\"cl\">Payment</span>()\n    <span class=\"dc\">self._shp</span> = <span class=\"cl\">Shipping</span>()\n\n  <span class=\"kw\">def</span> <span class=\"fn\">place_order</span>(<span class=\"dc\">self</span>, <span class=\"dc\">sku</span>: <span class=\"kw\">str</span>, <span class=\"dc\">price</span>: <span class=\"kw\">float</span>) -&gt; <span class=\"kw\">str</span>:\n    <span class=\"kw\">if not</span> <span class=\"dc\">self._inv</span>.<span class=\"fn\">check</span>(<span class=\"dc\">sku</span>):\n      <span class=\"kw\">raise</span> <span class=\"cl\">ValueError</span>(<span class=\"st\">\"Out of stock\"</span>)\n    <span class=\"dc\">self._pay</span>.<span class=\"fn\">charge</span>(<span class=\"dc\">price</span>)\n    <span class=\"kw\">return</span> <span class=\"dc\">self._shp</span>.<span class=\"fn\">ship</span>(<span class=\"dc\">sku</span>)\n\n<span class=\"cm\"># tracking = OrderFacade().place_order(\"SKU-001\", 99.90)</span>",
    "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">OrderFacade</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>\n    <span class=\"dc\">@inv</span>, <span class=\"dc\">@pay</span>, <span class=\"dc\">@shp</span> =\n      <span class=\"cl\">Inventory</span>.<span class=\"fn\">new</span>, <span class=\"cl\">Payment</span>.<span class=\"fn\">new</span>, <span class=\"cl\">Shipping</span>.<span class=\"fn\">new</span>\n  <span class=\"kw\">end</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">place_order</span>(<span class=\"dc\">sku</span>, <span class=\"dc\">price</span>)\n    <span class=\"kw\">raise</span> <span class=\"st\">\"Out of stock\"</span> <span class=\"kw\">unless</span> <span class=\"dc\">@inv</span>.<span class=\"fn\">check</span>(<span class=\"dc\">sku</span>)\n    <span class=\"dc\">@pay</span>.<span class=\"fn\">charge</span>(<span class=\"dc\">price</span>)\n    <span class=\"dc\">@shp</span>.<span class=\"fn\">ship</span>(<span class=\"dc\">sku</span>)\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>",
