    "C#": "<span class=\"kw\">public record</span> <span class=\"cl\">TreeType</span>(<span class=\"kw\">string</span> <span class=\"dc\">Name</span>, <span class=\"kw\">string</span> <span class=\"dc\">Color</span>);\n\n<span class=\"kw\">public static class</span> <span class=\"cl\">TreeFactory</span> {\n  <span class=\"kw\">static readonly</span> <span class=\"cl\">Dictionary</span>&lt;<span class=\"kw\">string</span>,<span class=\"cl\">TreeType</span>&gt; <span class=\"dc\">_c</span> = <span class=\"kw\">new</span>();\n\n  <span class=\"kw\">public static</span> <span class=\"cl\">TreeType</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">n</span>, <span class=\"kw\">string</span> <span class=\"dc\">c</span>) {\n    <span class=\"kw\">var</span> <span class=\"dc\">k</span> = <span class=\"dc\">n</span> + <span class=\"dc\">c</span>;\n    <span class=\"kw\">if</span> (!<span class=\"dc\">_c</span>.<span class=\"fn\">ContainsKey</span>(<span class=\"dc\">k</span>)) <span class=\"dc\">_c</span>[<span class=\"dc\">k</span>] = <span class=\"kw\">new</span>(<span class=\"dc\">n</span>, <span class=\"dc\">c</span>);\n    <span class=\"kw\">return</span> <span class=\"dc\">_c</span>[<span class=\"dc\">k</span>];\n  }\n}",
    "Python": "<span class=\"kw\">class</span> <span class=\"cl\">TreeFactory</span>:\n  <span class=\"dc\">_cache</span>: <span class=\"kw\">dict</span> = {}\n\n  <span class=\"dc\">@classmethod</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">get</span>(<span class=\"dc\">cls</span>, <span class=\"dc\">name</span>, <span class=\"dc\">color</span>):\n    <span class=\"dc\">key</span> = (<span class=\"dc\">name</span>, <span class=\"dc\">color</span>)\n    <span class=\"kw\">if</span> <span class=\"dc\">key</span> <span class=\"kw\">not in</span> <span class=\"dc\">cls._cache</span>:\n      <span class=\"dc\">cls._cache</span>[<span class=\"dc\">key</span>] = {<span class=\"st\">\"name\"</span>: <span class=\"dc\">name</span>, <span class=\"st\">\"color\"</span>: <span class=\"dc\">color</span>}\n    <span class=\"kw\">return</span> <span class=\"dc\">cls._cache</span>[<span class=\"dc\">key</span>]",
    "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">TreeFactory</span>\n  <span class=\"dc\">@@cache</span> = {}\n\n  <span class=\"kw\">def</span> <span class=\"dc\">self</span>.<span class=\"fn\">get</span>(<span class=\"dc\">name</span>, <span class=\"dc\">color</span>)\n    <span class=\"dc\">key</span> = <span class=\"st\">\"#{{name}}#{{color}}\"</span>\n    <span class=\"dc\">@@cache</span>[<span class=\"dc\">key</span>] ||= { name: <span class=\"dc\">name</span>, color: <span class=\"dc\">color</span> }\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>",
