    "C#": "<span class=\"kw\">public class</span> <span class=\"cl\">Editor</span> {\n  <span class=\"kw\">string</span> <span class=\"dc\">_t</span> = <span class=\"st\">\"\"</span>;\n  <span class=\"kw\">public record</span> <span class=\"cl\">Snap</span>(<span class=\"kw\">string</span> <span class=\"dc\">T</span>);\n\n  <span class=\"kw\">public void</span> <span class=\"fn\">Type</span>(<span class=\"kw\">string</span> <span class=\"dc\">s</span>) =&gt; <span class=\"dc\">_t</span> += <span class=\"dc\">s</span>;\n  <span class=\"kw\">public</span> <span class=\"cl\">Snap</span> <span class=\"fn\">Save</span>()              =&gt; <span class=\"kw\">new</span>(<span class=\"dc\">_t</span>);\n  <span class=\"kw\">public void</span> <span class=\"fn\">Restore</span>(<span class=\"cl\">Snap</span> <span class=\"dc\">s</span>) =&gt; <span class=\"dc\">_t</span> = <span class=\"dc\">s</span>.<span class=\"dc\">T</span>;\n  <span class=\"kw\">public string</span> <span class=\"dc\">Text</span> =&gt; <span class=\"dc\">_t</span>;\n}",
    "Python": "<span class=\"kw\">class</span> <span class=\"cl\">Editor</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>): <span class=\"dc\">self._t</span> = <span class=\"st\">\"\"</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">type</span>(<span class=\"dc\">self</span>, <span class=\"dc\">s</span>): <span class=\"dc\">self._t</span> += <span class=\"dc\">s</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">save</span>(<span class=\"dc\">self</span>): <span class=\"kw\">return</span> <span class=\"dc\">self._t</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">restore</span>(<span class=\"dc\">self</span>, <span class=\"dc\">snap</span>): <span class=\"dc\">self._t</span> = <span class=\"dc\">snap</span>\n\n\n<span class=\"dc\">e</span> = <span class=\"cl\">Editor</span>()\n<span class=\"dc\">e</span>.<span class=\"fn\">type</span>(<span class=\"st\">\"Hello\"</span>)\n<span class=\"dc\">s</span> = <span class=\"dc\">e</span>.<span class=\"fn\">save</span>()\n<span class=\"dc\">e</span>.<span class=\"fn\">type</span>(<span class=\"st\">\" World\"</span>)\n<span class=\"dc\">e</span>.<span class=\"fn\">restore</span>(<span class=\"dc\">s</span>)\n<span class=\"fn\">print</span>(<span class=\"dc\">e</span>.<span class=\"fn\">save</span>())  <span class=\"cm\"># Hello</span>",
    "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">Editor</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span> = <span class=\"dc\">@t</span> = <span class=\"st\">\"\"</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">type</span>(<span class=\"dc\">s</span>) = <span class=\"dc\">@t</span> += <span class=\"dc\">s</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">save</span>        = <span class=\"dc\">@t</span>.<span class=\"fn\">dup</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">restore</span>(<span class=\"dc\">snap</span>) = <span class=\"dc\">@t</span> = <span class=\"dc\">snap</span>\n  <span class=\"dc\">attr_reader</span> <span class=\"st\">:t</span>\n<span class=\"kw\">end</span>\n\n<span class=\"dc\">e</span> = <span class=\"cl\">Editor</span>.<span class=\"fn\">new</span>\n<span class=\"dc\">e</span>.<span class=\"fn\">type</span>(<span class=\"st\">\"Hello\"</span>); <span class=\"dc\">s</span> = <span class=\"dc\">e</span>.<span class=\"fn\">save</span>\n<span class=\"dc\">e</span>.<span class=\"fn\">type</span>(<span class=\"st\">\" World\"</span>); <span class=\"dc\">e</span>.<span class=\"fn\">restore</span>(<span class=\"dc\">s</span>)\n<span class=\"fn\">puts</span> <span class=\"dc\">e</span>.<span class=\"dc\">t</span>  <span class=\"cm\"># Hello</span>",
