  "p21": {
    "Java": "<span class=\"kw\">abstract class</span> <span class=\"cl\">DataParser</span> {\n  <span class=\"cm\">// Template method \u2014 final!</span>\n  <span class=\"kw\">public final void</span> <span class=\"fn\">parse</span>(<span class=\"cl\">String</span> <span class=\"dc\">file</span>) {\n    <span class=\"fn\">open</span>(<span class=\"dc\">file</span>); <span class=\"fn\">read</span>(); <span class=\"fn\">process</span>(); <span class=\"fn\">close</span>();\n  }\n\n  <span class=\"kw\">protected abstract void</span> <span class=\"fn\">read</span>();\n  <span class=\"kw\">protected abstract void</span> <span class=\"fn\">process</span>();\n\n  <span class=\"kw\">private void</span> <span class=\"fn\">open</span>(<span class=\"cl\">String</span> <span class=\"dc\">f</span>) {\n    <span class=\"cl\">System</span>.out.<span class=\"fn\">println</span>(<span class=\"st\">\"Open: \"</span> + <span class=\"dc\">f</span>);\n  }\n  <span class=\"kw\">private void</span> <span class=\"fn\">close</span>() {\n    <span class=\"cl\">System</span>.out.<span class=\"fn\">println</span>(<span class=\"st\">\"Close\"</span>);\n  }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">CsvParser</span> <span class=\"kw\">extends</span> <span class=\"cl\">DataParser</span> {\n  <span class=\"kw\">protected void</span> <span class=\"fn\">read</span>()    { <span class=\"cl\">System</span>.out.<span class=\"fn\">println</span>(<span class=\"st\">\"Read CSV\"</span>); }\n  <span class=\"kw\">protected void</span> <span class=\"fn\">process</span>() { <span class=\"cl\">System</span>.out.<span class=\"fn\">println</span>(<span class=\"st\">\"Process CSV\"</span>); }\n}",
    "C#": "<span class=\"kw\">public abstract class</span> <span class=\"cl\">DataParser</span> {\n  <span class=\"kw\">public sealed void</span> <span class=\"fn\">Parse</span>(<span class=\"kw\">string</span> <span class=\"dc\">file</span>) {\n    <span class=\"fn\">Open</span>(<span class=\"dc\">file</span>); <span class=\"fn\">Read</span>(); <span class=\"fn\">Process</span>(); <span class=\"fn\">Close</span>();\n  }\n\n  <span class=\"kw\">protected abstract void</span> <span class=\"fn\">Read</span>();\n  <span class=\"kw\">protected abstract void</span> <span class=\"fn\">Process</span>();\n\n  <span class=\"kw\">void</span> <span class=\"fn\">Open</span>(<span class=\"kw\">string</span> <span class=\"dc\">f</span>) =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">$\"Open: {{f}}\"</span>);\n  <span class=\"kw\">void</span> <span class=\"fn\">Close</span>() =&gt; <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">\"Close\"</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">CsvParser</span> : <span class=\"cl\">DataParser</span> {\n  <span class=\"kw\">protected override void</span> <span class=\"fn\">Read</span>() =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">\"Read CSV\"</span>);\n  <span class=\"kw\">protected override void</span> <span class=\"fn\">Process</span>() =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">\"Process CSV\"</span>);\n}",
    "Python": "<span class=\"kw\">from</span> abc <span class=\"kw\">import</span> <span class=\"cl\">ABC</span>, abstractmethod\n\n<span class=\"kw\">class</span> <span class=\"cl\">DataParser</span>(<span class=\"cl\">ABC</span>):\n  <span class=\"kw\">def</span> <span class=\"fn\">parse</span>(<span class=\"dc\">self</span>, <span class=\"dc\">file</span>):  <span class=\"cm\"># \u2190 template</span>\n    <span class=\"dc\">self</span>.<span class=\"fn\">_open</span>(<span class=\"dc\">file</span>)\n    <span class=\"dc\">self</span>.<span class=\"fn\">read</span>()\n    <span class=\"dc\">self</span>.<span class=\"fn\">process</span>()\n    <span class=\"dc\">self</span>.<span class=\"fn\">_close</span>()\n\n  <span class=\"dc\">@abstractmethod</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">read</span>(<span class=\"dc\">self</span>): ...\n  <span class=\"dc\">@abstractmethod</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">process</span>(<span class=\"dc\">self</span>): ...\n\n  <span class=\"kw\">def</span> <span class=\"fn\">_open</span>(<span class=\"dc\">self</span>, <span class=\"dc\">f</span>): <span class=\"fn\">print</span>(<span class=\"st\">f\"Open: {{f}}\"</span>)\n  <span class=\"kw\">def</span> <span class=\"fn\">_close</span>(<span class=\"dc\">self</span>):  <span class=\"fn\">print</span>(<span class=\"st\">\"Close\"</span>)",
    "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">DataParser</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">parse</span>(<span class=\"dc\">file</span>) <span class=\"cm\"># template</span>\n    <span class=\"fn\">open_file</span>(<span class=\"dc\">file</span>); <span class=\"fn\">read</span>; <span class=\"fn\">process</span>; <span class=\"fn\">close_file</span>\n  <span class=\"kw\">end</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">open_file</span>(<span class=\"dc\">f</span>) = <span class=\"fn\">puts</span> <span class=\"st\">\"Open: #{{f}}\"</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">close_file</span>  = <span class=\"fn\">puts</span> <span class=\"st\">\"Close\"</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">read</span>    = <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">process</span> = <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">CsvParser</span> &lt; <span class=\"cl\">DataParser</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">read</span>    = <span class=\"fn\">puts</span> <span class=\"st\">\"Read CSV\"</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">process</span> = <span class=\"fn\">puts</span> <span class=\"st\">\"Process CSV\"</span>\n<span class=\"kw\">end</span>",
  },
