    "C#": "<span class=\"kw\">public interface</span> <span class=\"cl\">IVisitor</span> {\n  <span class=\"kw\">void</span> <span class=\"fn\">Visit</span>(<span class=\"cl\">Book</span> <span class=\"dc\">b</span>);\n  <span class=\"kw\">void</span> <span class=\"fn\">Visit</span>(<span class=\"cl\">Food</span> <span class=\"dc\">f</span>);\n}\n\n<span class=\"kw\">public record</span> <span class=\"cl\">Book</span>(<span class=\"kw\">decimal</span> <span class=\"dc\">Price</span>) {\n  <span class=\"kw\">public void</span> <span class=\"fn\">Accept</span>(<span class=\"cl\">IVisitor</span> <span class=\"dc\">v</span>) =&gt; <span class=\"dc\">v</span>.<span class=\"fn\">Visit</span>(<span class=\"dc\">this</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">TaxVisitor</span> : <span class=\"cl\">IVisitor</span> {\n  <span class=\"kw\">public void</span> <span class=\"fn\">Visit</span>(<span class=\"cl\">Book</span> <span class=\"dc\">b</span>) =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">$\"Tax: R${{b.Price*.1m:N2}}\"</span>);\n  <span class=\"kw\">public void</span> <span class=\"fn\">Visit</span>(<span class=\"cl\">Food</span> <span class=\"dc\">_</span>) =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">\"Food: isento\"</span>);\n}",
